    uint32_t totalRows = 1;
    for (uint32_t i = 0; i < ndim - 1; ++i) {
        totalRows *= static_cast<uint32_t>(origin_shape.GetDim(i));
    }
    if (totalRows == 0 || reductionLen == 0) {
        return ge::GRAPH_FAILED;
